import requests

def fetch_url_content(url, headers=None, params=None, timeout=10):
    """
    Fetch and return the content of a given URL.
    
    Args:
        url (str): The URL to fetch.
        headers (dict, optional): Optional headers to include in the request.
        params (dict, optional): Optional query parameters.
        timeout (int, optional): Timeout for the request in seconds.

    Returns:
        dict: A dictionary containing status code, headers, and content.
    """
    try:
        response = requests.get(url, headers=headers, params=params, timeout=timeout)
        response.raise_for_status()
        return {
            'status_code': response.status_code,
            'headers': dict(response.headers),
            'content': response.text
        }
    except requests.exceptions.RequestException as e:
        return {
            'error': str(e)
        }

# Example usage:
if __name__ == "__main__":
    url = input("Enter the URL to fetch: ")
    result = fetch_url_content(url)
    print(result)